#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_K 100000
#define MAX_N 1000000000
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int k;
        scanf("%d", &k);
        int hints[k][3]; // operator, value, logical_value
        for (int i = 0; i < k; i++) {
            char operator;
            int value;
            char logical_value[4];
            scanf(" %c %d %s", &operator, &value, logical_value);
            hints[i][0] = operator;
            hints[i][1] = value;
            hints[i][2] = (logical_value[0] == 'Y') ? 1 : 0;
        }
        int possible_values[k + 2];
        int count = 0;
        for (int i = 0; i < k; i++) {
            possible_values[count++] = hints[i][1];
        }
        possible_values[count++] = 1;
        possible_values[count++] = MAX_N;
        qsort(possible_values, count, sizeof(int), compare);
        int min_lies = MAX_N;
        for (int i = 0; i < count; i++) {
            int lies = 0;
            for (int j = 0; j < k; j++) {
                if (hints[j][0] == '<') {
                    if (possible_values[i] >= hints[j][1] && hints[j][2] == 1) lies++;
                    if (possible_values[i] < hints[j][1] && hints[j][2] == 0) lies++;
                } else if (hints[j][0] == '>') {
                    if (possible_values[i] <= hints[j][1] && hints[j][2] == 1) lies++;
                    if (possible_values[i] > hints[j][1] && hints[j][2] == 0) lies++;
                } else {
                    if (possible_values[i] != hints[j][1] && hints[j][2] == 1) lies++;
                    if (possible_values[i] == hints[j][1] && hints[j][2] == 0) lies++;
                }
            }
            min_lies = (lies < min_lies) ? lies : min_lies;
        }
        printf("%d\n", min_lies);
    }
    return 0;
}

